tasks.starter:
// IAM 역할이 정적 자격증명보다 우수한 이유를 코드 주석으로 설명하라:
// ...

// withCredentials를 사용한 수정된 'Push to ECR' 스테이지 (폴백 방식)
stage('Push to ECR') {
    steps {
        // 저장된 AWS 키 페어를 주입하는 withCredentials를 사용
        // Jenkins의 자격증명 ID: 'aws-ecr-creds' (Username+Password 또는 AWS 자격증명 유형)
        withCredentials([/* 채워 넣기 */]) {
            sh """
              aws ecr get-login-password --region ${AWS_REGION} \\
                | docker login --username AWS --password-stdin ${REGISTRY}
              docker push ${REGISTRY}/${ECR_REPO}:${IMAGE_TAG}
            """
        }
    }
}

tasks.solution:
// IAM 역할이 우수한 이유:
// 1. 교체·유출·소스에 실수로 커밋할 정적 자격증명이 없다.
// 2. AWS가 자동으로 자격증명을 교체한다 (STS 단기 토큰).
// 3. 역할을 정밀하게 감사하고 범위를 제한할 수 있다 (예: 특정 리포지토리에만
//    ecr:GetAuthorizationToken과 ecr:BatchCheckLayerAvailability/PutImage).
// 4. Jenkins 호스트가 침해되더라도 토큰이 분 단위로 만료되므로
//    자격증명 노출 시간이 최소화된다.

// 폴백: withCredentials로 저장된 자격증명 주입
stage('Push to ECR') {
    steps {
        withCredentials([[
            $class: 'AmazonWebServicesCredentialsBinding',
            credentialsId: 'aws-ecr-creds',
            accessKeyVariable: 'AWS_ACCESS_KEY_ID',
            secretKeyVariable: 'AWS_SECRET_ACCESS_KEY'
        ]]) {
            sh """
              aws ecr get-login-password --region ${AWS_REGION} \\
                | docker login --username AWS --password-stdin ${REGISTRY}
              docker push ${REGISTRY}/${ECR_REPO}:${IMAGE_TAG}
            """
        }
    }
}
